#' Load and process fire data function to be wrapped with LaF::process_blocks
#'
#' This is a function used within LaF::process_blocks to read chunks of a
#' (too large for memory) weather data file, filter them according to fire-days and output a smaller
#' table to be used in the Biomass_fireWeather module. The function uses cffdr::fwi internally
#' to calculate FWI (with default `init`).
#'
#' @param d the data blocks being generated by LaF::process_blocks
#' @param prevBlock result of the function call that
#' @param projectWeatherData do weather table coordinates need to be projected?
#' @param crsProj if `projectWeatherData` is TRUE, what should be the final projection?
#'  Note that it needs to be compatible with cffdr::fwi
#' @param origCrsProj what is the original projection of the data coordinates?
#' @param FWIthresh what is the threshold (minimum or equal) FWI value to define a weather day?
#'
#' @return a sumamrized version of the original table, subset to fire-day-like weather
#'
#' @seealso \code{cffdr::fwi}
#' @seealso \code{LaF::process_blocks}
#' @export
#' @importFrom cffdrs fwi
#' @importFrom data.table data.table rbind.data.table cbind.data.table
#' @importFrom sf st_as_sf st_coordinates st_transform

loadAndProcessWeatherData <- function (d, prevBlock, projectWeatherData, crsProj,
                                       origCrsProj, FWIthresh, timePeriod, weatherDataLastYear) {
  if (!nrow(d))
    return(prevBlock)

  ## make temporary obj
  prevData <- data.table(d)

  ## convert to sf
  prevData <- st_as_sf(prevData, coords = c("Longitude", "Latitude"),
                       crs = origCrsProj, agr = "constant")
  ## project if need be
  if (projectWeatherData)
    prevData <- st_transform(prevData, crs = crsProj)

  ## get coordinates and convert back to DT and re-add coordinates
  coords <- st_coordinates(prevData)
  prevData <- data.table(st_drop_geometry(prevData))
  colnames(coords) <- c("Longitude", "Latitude")

  prevData <- cbind(prevData, data.table(coords))

  ## reduce weather data to fire days (FWI >= FWIthresh)
  FWIinputs <- data.frame(id = 1:nrow(prevData),
                          lat = prevData$Latitude,
                          long = prevData$Longitude,
                          yr = prevData$Year,
                          mon = prevData$Month,
                          day = prevData$Day,
                          temp = prevData$Air.Temperature,
                          rh = prevData$Relative.Humidity,
                          ws = prevData$Wind.Speed.at.10.meters,
                          prec = prevData$Total.Precipitation)

  ## use fwi() defaults to initialise
  FWIinit <- data.frame(ffmc = 85, dmc = 6, dc = 15)

  FWIoutputs <- suppressWarnings({
    fwi(input = FWIinputs,
        init = FWIinit,
        batch = FALSE,
        lat.adjust = TRUE)
  })
  FWIoutputs <- data.table(FWIoutputs)

  ## subset weatherData to fire days
  toKeep <- FWIoutputs$FWI >= FWIthresh
  weatherData <- prevData[toKeep,]

  ## reduce weather data to appropriate time period for MDC
  timePeriod <- timePeriod - weatherDataLastYear
  FWIoutputs <- FWIoutputs[YR %in% timePeriod & MON == 7]

  ## average July DC per year to make weatherDataMDC
  weatherDataMDC <- FWIoutputs[, list(julMDC = mean(DC)), by = .(LAT, LONG, YR)]

  if (is.null(prevBlock)) {
    prevBlock <- list("weatherData" = weatherData, "weatherDataMDC" = weatherDataMDC)
  } else {
      prevBlock$weatherData <- rbind(prevBlock$weatherData, weatherData, use.names = TRUE)
      prevBlock$weatherDataMDC <- rbind(prevBlock$weatherDataMDC, weatherDataMDC, use.names = TRUE)
    }
  return(prevBlock)
}
